17	export function isJSONSerializable(value: any): boolean {
18	  if (value === undefined) {
19	    return false;
20	  }
21	  const t = typeof value;
22	  if (t === "string" || t === "number" || t === "boolean" || t === null) {
23	    return true;
24	  }
25	  if (t !== "object") {
26	    return false; // bigint, function, symbol, undefined
27	  }
28	  if (Array.isArray(value)) {
29	    return true;
30	  }
31	  if (value.buffer) {
32	    return false;
33	  }
34	  // `FormData` and `URLSearchParams` should't have a `toJSON` method,
35	  // but Bun adds it, which is non-standard.
36	  if (value instanceof FormData || value instanceof URLSearchParams) {
37	    return false;
38	  }
39	  return (
40	    (value.constructor && value.constructor.name === "Object") ||
41	    typeof value.toJSON === "function"
42	  );
43	}
44	
45	const textTypes = new Set([
46	  "image/svg",
47	  "application/xml",
48	  "application/xhtml",
49	  "application/html",
50	]);
51	
52	const JSON_RE = /^application\/(?:[\w!#$%&*.^`~-]*\+)?json(;.+)?$/i;
53	
54	// This provides reasonable defaults for the correct parser based on Content-Type header.
55	export function detectResponseType(_contentType = ""): ResponseType {
56	  if (!_contentType) {
57	    return "json";
58	  }
59	
60	  // Value might look like: `application/json; charset=utf-8`
61	  const contentType = _contentType.split(";").shift() || "";
62	
63	  if (JSON_RE.test(contentType)) {
64	    return "json";
65	  }
66	
67	  // TODO
68	  // if (contentType === 'application/octet-stream') {
69	  //   return 'stream'
70	  // }
71	
72	  // SSE
73	  // https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events/Using_server-sent_events#sending_events_from_the_server
74	  if (contentType === "text/event-stream") {
75	    return "stream";
76	  }
77	
78	  if (textTypes.has(contentType) || contentType.startsWith("text/")) {
79	    return "text";
80	  }
81	
82	  return "blob";
83	}
