85	export function resolveFetchOptions<
86	  R extends ResponseType = ResponseType,
87	  T = any,
88	>(
89	  request: FetchRequest,
90	  input: FetchOptions<R, T> | undefined,
91	  defaults: FetchOptions<R, T> | undefined,
92	  Headers: typeof globalThis.Headers
93	): ResolvedFetchOptions<R, T> {
94	  // Merge headers
95	  const headers = mergeHeaders(
96	    input?.headers ?? (request as Request)?.headers,
97	    defaults?.headers,
98	    Headers
99	  );
100	
101	  // Merge query/params
102	  let query: Record<string, any> | undefined;
103	  if (defaults?.query || defaults?.params || input?.params || input?.query) {
104	    query = {
105	      ...defaults?.params,
106	      ...defaults?.query,
107	      ...input?.params,
108	      ...input?.query,
109	    };
110	  }
111	
112	  return {
113	    ...defaults,
114	    ...input,
115	    query,
116	    params: query,
117	    headers,
118	  };
119	}
120	
121	function mergeHeaders(
122	  input: HeadersInit | undefined,
123	  defaults: HeadersInit | undefined,
124	  Headers: typeof globalThis.Headers
125	): Headers {
126	  if (!defaults) {
127	    return new Headers(input);
128	  }
129	  const headers = new Headers(defaults);
130	  if (input) {
131	    for (const [key, value] of Symbol.iterator in input || Array.isArray(input)
132	      ? input
133	      : new Headers(input)) {
134	      headers.set(key, value);
135	    }
136	  }
137	  return headers;
138	}
