// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
const DEFAULT_FAILURE_STATUS_CODES = [
  408, // Request Timeout
  409, // Conflict
  425, // Too Early (Experimental)
  429, // Too Many Requests
  500, // Internal Server Error
  502, // Bad Gateway
  503, // Service Unavailable
  504, // Gateway Timeout
