const DEFAULT_THRESHOLD = 5;
const DEFAULT_COOLDOWN = 30_000;
const DEFAULT_HALF_OPEN_MAX_REQUESTS = 1;

export interface CircuitBreakerOptions {
  /** Number of consecutive failures before the circuit opens. */
  threshold: number;
  /** Time in milliseconds the circuit stays open before allowing a half-open probe. */
  cooldown: number;
  /** Maximum number of concurrent probes allowed while half-open. */
  halfOpenMaxRequests?: number;
  /** Response status codes that count as circuit failures. */
  failureStatusCodes?: number[];
}

/**
 * Circuit breaker request option.
 *
 * - `true` enables the circuit breaker with default settings.
 * - An object customizes the behavior.
 * - Omitting or a falsy value disables circuit tracking and blocking.
 */
export type CircuitBreakerOption = boolean | CircuitBreakerOptions;

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: Set<number>;
}

export type CircuitStatus = "closed" | "open" | "half-open";

interface CircuitEntry {
  status: CircuitStatus;
  /** Consecutive failures while closed. */
  failures: number;
  /** Timestamp (`Date.now()`) the circuit last transitioned to open. */
  openedAt: number;
  /** In-flight probes while half-open. */
  halfOpenActive: number;
}

export type CircuitStore = Map<string, CircuitEntry>;

/**
 * Normalizes the `circuitBreaker` request option into resolved options.
 * Returns `undefined` when the circuit breaker is disabled.
 */
export function resolveCircuitBreakerOptions(
  option: CircuitBreakerOption | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!option) {
    return undefined;
  }
  const input: Partial<CircuitBreakerOptions> = option === true ? {} : option;
  return {
    threshold: input.threshold ?? DEFAULT_THRESHOLD,
    cooldown: input.cooldown ?? DEFAULT_COOLDOWN,
    halfOpenMaxRequests:
      input.halfOpenMaxRequests ?? DEFAULT_HALF_OPEN_MAX_REQUESTS,
    failureStatusCodes: new Set(
      input.failureStatusCodes ?? DEFAULT_FAILURE_STATUS_CODES
    ),
  };
}

/**
 * Resolves the origin used to key circuit state for a given request.
 * Supports `string`, `URL`, and `Request` inputs. Returns `undefined`
 * when the origin cannot be determined (for example, a relative string
 * without a resolvable base).
 */
export function getRequestOrigin(request: FetchRequest): string | undefined {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    if (typeof Request !== "undefined" && request instanceof Request) {
      return new URL(request.url).origin;
    }
    const url = (request as { url?: string })?.url ?? String(request);
    return new URL(url).origin;
  } catch {
    return undefined;
  }
}

function getEntry(store: CircuitStore, key: string): CircuitEntry {
  let entry = store.get(key);
  if (!entry) {
    entry = { status: "closed", failures: 0, openedAt: 0, halfOpenActive: 0 };
    store.set(key, entry);
  }
  return entry;
}

export interface AcquireResult {
  /** Whether the request is blocked (fast-fail). */
  blocked: boolean;
  /** Whether this request holds a half-open probe slot. */
  isProbe: boolean;
}

/**
 * Attempts to acquire the circuit for a logical request.
 * Handles the `open` -> `half-open` cooldown transition and half-open
 * quota gating. Mutates the entry to reserve a probe slot when relevant.
 */
export function tryAcquire(
  store: CircuitStore,
  key: string,
  options: ResolvedCircuitBreakerOptions,
  now: number
): AcquireResult {
  const entry = getEntry(store, key);

  if (entry.status === "open") {
    if (now - entry.openedAt >= options.cooldown) {
      entry.status = "half-open";
      entry.halfOpenActive = 0;
    } else {
      return { blocked: true, isProbe: false };
    }
  }

