    if (entry.halfOpenActive >= options.halfOpenMaxRequests) {
      return { blocked: true, isProbe: false };
    }
    entry.halfOpenActive += 1;
    return { blocked: false, isProbe: true };
  }

  // closed
  return { blocked: false, isProbe: false };
}

/** Records a successful logical request, closing the circuit. */
export function recordSuccess(
  store: CircuitStore,
  key: string,
  isProbe: boolean
): void {
  const entry = getEntry(store, key);
  if (isProbe && entry.halfOpenActive > 0) {
    entry.halfOpenActive -= 1;
  }
  entry.status = "closed";
  entry.failures = 0;
}

/** Records a failed logical request, opening the circuit when warranted. */
export function recordFailure(
  store: CircuitStore,
  key: string,
  options: ResolvedCircuitBreakerOptions,
  isProbe: boolean,
  now: number
): void {
  const entry = getEntry(store, key);

  if (isProbe) {
    // A failed half-open probe re-opens the circuit and restarts cooldown.
    if (entry.halfOpenActive > 0) {
      entry.halfOpenActive -= 1;
    }
    entry.status = "open";
    entry.openedAt = now;
    return;
  }

  entry.failures += 1;
  if (entry.failures >= options.threshold) {
    entry.status = "open";
    entry.openedAt = now;
  }
}

